      <div className="glass-sm" style={{ overflow:'hidden' }}>
        <div style={{ overflowX:'auto' }}>
          <table className="tbl">
            <thead><tr><th>Visitor</th><th>Phone</th><th>Visiting</th><th>Unit</th><th>Check-in</th><th>Check-out</th><th>Purpose</th><th>Status</th></tr></thead>
            <tbody>
